+
+  ASSERT_TRUE(!controller_->admittance_->parameters_.state_interfaces.empty());
+  ASSERT_TRUE(
+    controller_->admittance_->parameters_.state_interfaces.size() == state_interface_types_.size());
+  ASSERT_TRUE(std::equal(
