+TEST_F(RangeSensorBroadcasterTest, Publish_RangeBroadcaster_Success)
+{
+  init_broadcaster("test_range_sensor_broadcaster");
+
+  range_broadcaster_->on_configure(rclcpp_lifecycle::State());
