+    front_wheels_names_[0] + "/" + steering_interface_name_);
+  EXPECT_EQ(
+    command_intefaces.names[CMD_STEER_LEFT_WHEEL],
+    front_wheels_names_[1] + "/" + steering_interface_name_);
