+  publish_commands();
+  ASSERT_TRUE(controller_->wait_for_commands(executor));
+
+  ASSERT_EQ(
+    controller_->update(rclcpp::Time(0, 0, RCL_ROS_TIME), rclcpp::Duration::from_seconds(0.01)),
+    controller_interface::return_type::OK);
