+  void subscribe_and_get_messages(ControllerStateMsg & msg)
+  {
+    // create a new subscriber
+    rclcpp::Node test_subscription_node("test_subscription_node");
+    auto subs_callback = [&](const ControllerStateMsg::SharedPtr) {};
