+  ASSERT_EQ(state_intefaces.names.size(), joint_state_values_.size());
+  EXPECT_EQ(
+    state_intefaces.names[STATE_TRACTION_RIGHT_WHEEL],
+    controller_->rear_wheels_state_names_[0] + "/" + traction_interface_name_);
